        internal class MigrateAnswerCommands : PreferenceUpgrade(12) {
            override fun upgrade(preferences: SharedPreferences) {
                // Migrate FLIP_OR_ANSWER_RECOMMENDED bindings to FLIP_OR_ANSWER_EASE3
                migrateBinding(preferences, "binding_FLIP_OR_ANSWER_RECOMMENDED", "binding_FLIP_OR_ANSWER_EASE3")
                // Migrate FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED bindings to FLIP_OR_ANSWER_EASE4
                migrateBinding(preferences, "binding_FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED", "binding_FLIP_OR_ANSWER_EASE4")
            }

            private fun migrateBinding(preferences: SharedPreferences, oldKey: String, newKey: String) {
                if (!preferences.contains(oldKey)) {
                    Timber.v("No preference to migrate for key: '%s'", oldKey)
                    return
                }

                val oldBindings = preferences.getString(oldKey, null)
                if (oldBindings.isNullOrEmpty()) {
                    Timber.v("Empty preference for key: '%s'", oldKey)
                    preferences.edit { remove(oldKey) }
                    return
                }

                // Get existing bindings for the new key
                val existingBindings = preferences.getString(newKey, null)

                // Parse the old bindings
                val oldBindingsList = MappableBinding.fromPreferenceString(oldBindings)

                // Parse existing bindings
                val newBindingsList = if (existingBindings.isNullOrEmpty()) {
                    mutableListOf()
                } else {
                    MappableBinding.fromPreferenceString(existingBindings)
                }

                // Add old bindings to the new list (avoid duplicates)
                for (binding in oldBindingsList) {
                    if (!newBindingsList.contains(binding)) {
                        newBindingsList.add(binding)
                    }
                }

                Timber.i("Migrating preference from '%s' to '%s'", oldKey, newKey)

                // Save the merged bindings
                preferences.edit {
                    putString(newKey, newBindingsList.toPreferenceString())
                    remove(oldKey)
                }
            }
        }
    }
}"}

